  const [selectedStage, setSelectedStage]               = useState(null); // stage drill-down modal
  const [projectRemarks, setProjectRemarks]             = useState({});   // { project_id: "remark text" }
  const [stageModalFilters, setStageModalFilters]       = useState({});   // filters inside stage modal
  const [stageModalSort, setStageModalSort]             = useState({field:"delay_days",dir:"desc"});
  const [modalFilters, setModalFilters]                 = useState({});
